INSERT INTO sys_config (id, config_type, content_type, config_name, config_key, config_value, config_show, sort) VALUES (116, 6, 1, '底部菜单组 JSON', 'siteFooterMenusJson', '[{"group":"我是学员","items":[{"label":"请家教流程","href":"/help/request-process"},{"label":"请家教收费标准","href":"/zf"},{"label":"请家教常见问题","href":"/help/request-faq"},{"label":"怎样快速找到老师","href":"/help/find-tutor"}]},{"group":"我是教员","items":[{"label":"成为家教老师","href":"/help/become-tutor"},{"label":"家教课时费参考标准","href":"/zf"},{"label":"做家教收费标准","href":"/help/tutor-pricing"},{"label":"做家教常见问题","href":"/help/tutor-faq"}]},{"group":"关于我们","items":[{"label":"服务号","href":"/about/wechat"},{"label":"联系我们","href":"/about/contact"},{"label":"公司简介","href":"/about/intro"},{"label":"免责声明","href":"/agreement/disclaimer"},{"label":"隐私保护","href":"/agreement/privacy"}]}]', 1, 41) ON DUPLICATE KEY UPDATE config_type=VALUES(config_type), content_type=VALUES(content_type), config_name=VALUES(config_name), config_value=VALUES(config_value), config_show=VALUES(config_show), sort=VALUES(sort);
INSERT INTO sys_config (id, config_type, content_type, config_name, config_key, config_value, config_show, sort) VALUES (117, 6, 1, '价格说明列表 JSON', 'sitePriceNotesJson', '["以上价格为上门一对一辅导参考价格，在线辅导一般可享 8-9折 优惠。","艺术类（钢琴、美术、书法等）价格另议，通常高于文化课 20%-50%。","小语种（日语、法语、德语等）价格参考大学/成人栏目。","首次上课可安排免费试讲30分钟（需与教员协商）。","<strong>课时费由教员自定</strong>。续单课时费由家长直接结算给教员（不经平台）；首单课时费会作为教员侧中介费上缴客服，详见上方中介费政策。","以上价格仅供参考，具体价格请与教员沟通确认。"]', 1, 42) ON DUPLICATE KEY UPDATE config_type=VALUES(config_type), content_type=VALUES(content_type), config_name=VALUES(config_name), config_value=VALUES(config_value), config_show=VALUES(config_show), sort=VALUES(sort);
