INSERT INTO sys_config (id, config_type, content_type, config_name, config_key, config_value, config_show, sort) VALUES (140, 6, 1, '家教价格结构化数据 JSON', 'sitePricingData', '{"introPoints":["591家教网从数万教员库择优为您服务。","教员执教前，平台会进行严格的实名+学历认证。","对教员的每一份家教都有详细记录，供家长/学员参考。","平台对成功撮合的订单收取一次性中介费（家长 100 元 / 教员首单课时费），<b>续单 100% 归教员</b>，规则见 zf 页面下方说明。","如有任何疑问，请拨打客服热线。"],"categories":[{"title":"文化类家教价格","unit":"元/每小时","tables":[{"headers":["教员类型","学前/小学","初中","高中"],"rows":[["大学生","80-120","100-150","120-200"],["研究生","100-150","120-180","180-250"],["专职教员","120-180","150-220","200-300"],["在职教师","150-250","200-300","300-500"]]}],"notes":["英文版教材：在以上基础上价格有增加。","网络课程：相比上门辅导，费用降低 20%-30%，具体可商议。"]},{"title":"才艺运动类家教价格","unit":"元/每节课或每小时","tables":[{"headers":["教员类型","钢琴 / 小提琴 / 声乐等"],"rows":[["业余 8 级以上","120-200"],["专业大学生","150-300"],["名校专业大学生","180-300"],["专业音乐老师","200-400"]]},{"headers":["教员类型","美术 / 书法 / 体育 / 棋类等"],"rows":[["专业大学生","100-200"],["专业老师","150-300"]]}],"notes":["艺术类价格与乐器品类、授课时长、上课地点相关，以上为参考区间。","网络课程可降低 20%-30% 费用。"]},{"title":"语言留学类家教价格","unit":"元/每小时","tables":[{"headers":["教员类型","英语 / 口语 / 留学（托福、雅思、SAT、AP、A-level、IB）"],"rows":[["大学生","80-150"],["英语专业大学生","100-200"],["专业老师","150-300"],["海归外教","150-300"]]},{"headers":["教员类型","小语种（日、法、德、韩、西班牙等）"],"rows":[["专业大学生","100-150"],["专业老师","150-200"],["海外归国人员","150-300"]]}],"notes":["留学类考试辅导（SAT、A-level、IB 等）根据目标分差异较大，价格可在上述区间上浮。","网络课程可降低 20%-30% 费用。"]},{"title":"大学课程 / 计算机 / 考研类家教价格","unit":"元/每小时","tables":[{"headers":["教员类型","大学课程 / 计算机 / 考研"],"rows":[["专业大学生","100-200"],["专业老师","200-300"]]}],"notes":["高数、线代、离散、计算机专业课可协商。","考研辅导建议按课程包议价。","网络课程可降低 20%-30% 费用。"]}],"footnote":"★ 明星教员（带认证徽章、评价 4.8 分以上、带课 20+ 单）价格对应以上会适当上浮。"}', 0, 60) ON DUPLICATE KEY UPDATE config_type=VALUES(config_type), content_type=VALUES(content_type), config_name=VALUES(config_name), config_value=VALUES(config_value), config_show=VALUES(config_show), sort=VALUES(sort);
